// Merge data from both HTTP requests into a single structured object
const items = $input.all();

// Initialize containers for the data
let metricsData = null;
let biData = null;

// Process all input items to find data from both sources
for (const item of items) {
  // Check if this item came from Fetch Software Metrics
  if (item.json.metrics || item.json.software) {
    metricsData = item.json;
  }
  // Check if this item came from Fetch BI Dashboard Data
  else if (item.json.dashboard || item.json.bi) {
    biData = item.json;
  }
  // If the structure is unknown, try to identify by other characteristics
  else if (!metricsData) {
    metricsData = item.json;
  } else if (!biData) {
    biData = item.json;
  }
}

// Create the merged structured object
const mergedData = {
  metrics: metricsData || {},
  biData: biData || {},
  timestamp: new Date().toISOString()
};

// Return the merged data as a single item
return [{ json: mergedData }];

