// Comprehensive Audit Trail Log for GDPR and ISO Compliance

const timestamp = new Date().toISOString();
const inputData = $input.item.json;

// Extract anomaly details from previous nodes
const anomalyDetails = {
  detectedAt: timestamp,
  anomalyType: inputData.anomalyType || 'Unknown',
  severity: inputData.severity || 'Unknown',
  affectedSystems: inputData.affectedSystems || [],
  dataPoints: inputData.dataPoints || {},
  validationResults: inputData.validationResults || {},
  orchestrationDecisions: inputData.orchestrationDecisions || {}
};

// Extract actions taken
const actionsTaken = {
  alertsSent: inputData.alertsSent || [],
  remediationSteps: inputData.remediationSteps || [],
  escalationLevel: inputData.escalationLevel || 'None',
  automatedActions: inputData.automatedActions || []
};

// Extract notification channels used
const notificationChannels = {
  email: inputData.emailSent || false,
  slack: inputData.slackSent || false,
  recipients: inputData.recipients || [],
  messageIds: inputData.messageIds || []
};

// Compliance documentation
const complianceDocumentation = {
  gdprCompliance: {
    dataProcessingLawfulness: 'Automated monitoring for data integrity',
    legalBasis: 'Legitimate interest - Article 6(1)(f) GDPR',
    dataMinimization: 'Only necessary metrics collected',
    purposeLimitation: 'Data integrity and security monitoring',
    retentionPeriod: '90 days',
    dataSubjectRights: 'Audit logs available upon request'
  },
  isoCompliance: {
    standard: 'ISO 27001:2013',
    controlObjective: 'A.12.4.1 Event Logging',
    evidenceType: 'Automated audit trail',
    reviewFrequency: 'Real-time monitoring with daily reviews'
  }
};

// User approval status
const userApprovalStatus = {
  requiresApproval: inputData.severity === 'critical' || inputData.severity === 'high',
  approvalStatus: inputData.approvalStatus || 'Pending',
  approvedBy: inputData.approvedBy || null,
  approvalTimestamp: inputData.approvalTimestamp || null,
  approvalComments: inputData.approvalComments || ''
};

// Create comprehensive audit log entry
const auditLogEntry = {
  logId: `AUDIT-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
  timestamp: timestamp,
  workflowName: 'AI-Driven Data Integrity Monitoring',
  workflowExecutionId: $execution.id,
  anomalyDetails: anomalyDetails,
  actionsTaken: actionsTaken,
  notificationChannels: notificationChannels,
  complianceDocumentation: complianceDocumentation,
  userApprovalStatus: userApprovalStatus,
  metadata: {
    nodeExecutionId: $execution.id,
    executionMode: $execution.mode,
    retentionDate: new Date(Date.now() + 90 * 24 * 60 * 60 * 1000).toISOString(),
    complianceVersion: '1.0',
    auditTrailVersion: '2.0'
  }
};

// Log to console for debugging
console.log('Compliance Audit Trail Created:', auditLogEntry);

// Return the audit log entry
return {
  json: auditLogEntry
};
